        packet[15] = 0x00; // DSCP/ECN
        packet[16..18].copy_from_slice(&28u16.to_be_bytes()); // total length
        packet[23] = 17; // protocol: UDP
        packet[26..30].copy_from_slice(&[192, 168, 1, 1]); // src
        packet[30..34].copy_from_slice(&[10, 0, 0, 1]); // dst

