    #[test]
    fn test_parse_udp_packet() {
        let packet = build_test_udp_packet();
        let parsed = parse_packet(&packet).expect("failed to parse UDP packet");

        assert_eq!(parsed.ethernet.dst_mac, [0xaa, 0xbb, 0xcc, 0xdd, 0xee, 0xff]);
        assert_eq!(parsed.ethernet.src_mac, [0x11, 0x22, 0x33, 0x44, 0x55, 0x66]);
        assert_eq!(u16::from_be(parsed.ethernet.ether_type), 0x0800);

        let ipv4 = parsed.ipv4.expect("expected IPv4 header");
        assert_eq!((ipv4.version_ihl >> 4) & 0x0F, 4);
        assert_eq!(ipv4.protocol, 17);
        assert_eq!(ipv4.src_addr, [192, 168, 1, 1]);
        assert_eq!(ipv4.dst_addr, [10, 0, 0, 1]);

        match parsed.transport {
            TransportHeader::Udp(udp) => {
                assert_eq!(u16::from_be(udp.src_port), 8080);
                assert_eq!(u16::from_be(udp.dst_port), 53);
            }
            _ => panic!("expected UDP transport header"),
        }
    }

