    #[test]
    fn test_transmute_roundtrip_ethernet() {
        let header = EthernetHeader {
            dst_mac: [0xaa, 0xbb, 0xcc, 0xdd, 0xee, 0xff],
            src_mac: [0x11, 0x22, 0x33, 0x44, 0x55, 0x66],
            ether_type: 0x0008u16, // 0x0800 in network byte order on LE
        };

        let bytes = ethernet_header_to_bytes(header);
        let restored = unsafe { bytes_to_ethernet_header(bytes) };

        assert_eq!(header.dst_mac, restored.dst_mac);
        assert_eq!(header.src_mac, restored.src_mac);
        assert_eq!(header.ether_type, restored.ether_type);
    }

